const runStatus = $input.first().json;
const datasetId = runStatus?.data?.defaultDatasetId;
const runId = runStatus?.data?.id || 'unknown';

if (!datasetId) {
  return [{
    json: {
      error: true,
      message: 'No defaultDatasetId in run status. runId=' + runId + ' status=' + (runStatus?.data?.status || 'unknown')
    }
  }];
}

const token = 'YOUR_APIFY_TOKEN';

async function fetchDataset(dsId, attempt) {
  const url = `https://api.apify.com/v2/datasets/${dsId}/items?token=${token}`;
  const raw = await this.helpers.httpRequest({
    method: 'GET',
    url,
    encoding: 'utf-8',
    returnFullResponse: false,
    timeout: 60000,
    headers: { 'Accept': 'application/json' },
  });
  let parsed = raw;
  if (typeof raw === 'string') {
    try { parsed = JSON.parse(raw); } catch (e) {
      throw new Error(`JSON parse failed (attempt ${attempt}): ${raw.substring(0, 200)}`);
    }
  }
  return parsed;
}

let datasetItems;
let lastErr;
for (let attempt = 1; attempt <= 3; attempt++) {
  try {
    datasetItems = await fetchDataset.call(this, datasetId, attempt);
    if (Array.isArray(datasetItems) && datasetItems.length > 0) break;
    if (attempt < 3) {
      await new Promise(r => setTimeout(r, 15000));
    }
  } catch (err) {
    lastErr = err;
    if (attempt < 3) {
      await new Promise(r => setTimeout(r, 15000));
    }
  }
}

if (lastErr && (!datasetItems || !Array.isArray(datasetItems) || datasetItems.length === 0)) {
  return [{
    json: {
      error: true,
      message: `Fetch dataset failed after 3 attempts: ${lastErr.message}`,
      datasetId, runId
    }
  }];
}

if (!datasetItems || !Array.isArray(datasetItems) || datasetItems.length === 0) {
  return [{
    json: {
      error: true,
      message: `Dataset ${datasetId} empty after 3 attempts (runId=${runId}). Type=${typeof datasetItems}`,
      datasetId, runId
    }
  }];
}

const central = new Date().toLocaleDateString('en-CA', { timeZone: 'America/Chicago' });
const [cy,cm,cd] = central.split('-').map(Number);
const today = new Date(cy, cm-1, cd);
const day = today.getDay();
if (day === 0) today.setDate(today.getDate() - 2);
else if (day === 6) today.setDate(today.getDate() - 1);
const scrapeDate = today.getFullYear()+'-'+String(today.getMonth()+1).padStart(2,'0')+'-'+String(today.getDate()).padStart(2,'0');

// Separate flat agent records from the pool_data typed item
const agents = datasetItems.filter(item => !item._type);
const poolItem = datasetItems.find(item => item._type === 'pool_data');
const poolAgents = poolItem ? (poolItem.pool_agents || []) : [];
const poolInventory = poolItem ? (poolItem.pool_inventory || []) : [];

return [{
  json: {
    scrape_date: scrapeDate,
    agents: agents,
    pool_agents: poolAgents,
    pool_inventory: poolInventory
  }
}];

const payload = $node['Fetch Dataset & Build Payload'].json;
const agents = payload.agents || [];
const scrapeDate = payload.scrape_date;
const apikey = 'YOUR_SUPABASE_ANON_KEY';
const base = 'https://bcibmmbxrjfiulofserv.supabase.co/rest/v1';
const hdr = { 'apikey': apikey };

const roster = await this.helpers.httpRequest({ method:'GET', url: base+'/agents?select=name,site&is_active=eq.true', headers: hdr, json: true });
const siteMap = {};
for (const r of roster) siteMap[r.name] = r.site === 'AUS' ? 'ATX' : r.site === 'RMT' ? 'RMT' : 'CLT';

const yd = new Date(scrapeDate);
yd.setDate(yd.getDate() - 1);
if (yd.getDay() === 0) yd.setDate(yd.getDate() - 2);
if (yd.getDay() === 6) yd.setDate(yd.getDate() - 1);
const yesterdayStr = yd.toISOString().slice(0,10);
let yData = [];
try {
  yData = await this.helpers.httpRequest({ method:'GET', url: base+'/daily_scrape_data?select=agent_name,ib_sales,ob_sales,custom_sales,ib_premium,ob_premium,custom_premium,ib_leads_delivered,ob_leads_delivered&scrape_date=eq.'+yesterdayStr, headers: hdr, json: true });
} catch(e) {}

const ySites = { ATX: {s:0,p:0}, CLT: {s:0,p:0}, RMT: {s:0,p:0} };
for (const a of yData) {
  const site = siteMap[a.agent_name] || 'CLT';
  ySites[site].s += (a.ib_sales||0) + (a.ob_sales||0) + (a.custom_sales||0);
  ySites[site].p += (a.ib_premium||0) + (a.ob_premium||0) + (a.custom_premium||0);
}

const data = {};
for (const site of ['ATX','CLT','RMT']) data[site] = { T1:{s:0,p:0,n:0}, T2:{s:0,p:0,n:0}, T3:{s:0,p:0,n:0} };
const bonus = { ATX:{s:0,p:0}, CLT:{s:0,p:0}, RMT:{s:0,p:0} };
const leads = { ATX:{T1:0,T2:0,T3:0}, CLT:{T1:0,T2:0,T3:0}, RMT:{T1:0,T2:0,T3:0} };
const ib = { ATX:{leads:0,sales:0}, CLT:{leads:0,sales:0}, RMT:{leads:0,sales:0} };
const ob = { ATX:{leads:0,sales:0}, CLT:{leads:0,sales:0}, RMT:{leads:0,sales:0} };

for (const a of agents) {
  const site = siteMap[a.agent_name] || 'CLT';
  const tier = a.tier || 'T2';
  data[site][tier].s += (a.ib_sales||0) + (a.ob_sales||0);
  data[site][tier].p += (a.ib_premium||0) + (a.ob_premium||0);
  data[site][tier].n++;
  bonus[site].s += (a.custom_sales||0);
  bonus[site].p += (a.custom_premium||0);
  leads[site][tier] += (a.ib_leads_delivered||0) + (a.ob_leads_delivered||0);
  ib[site].leads += (a.ib_leads_delivered||0);
  ib[site].sales += (a.ib_sales||0);
  ob[site].leads += (a.ob_leads_delivered||0);
  ob[site].sales += (a.ob_sales||0);
}

const fmt = (n) => '$' + Math.round(n).toLocaleString();
const siteTotal = (site) => ({ sales: data[site].T1.s+data[site].T2.s+data[site].T3.s, premium: data[site].T1.p+data[site].T2.p+data[site].T3.p, agents: data[site].T1.n+data[site].T2.n+data[site].T3.n });
const atx = siteTotal('ATX');
const clt = siteTotal('CLT');
const rmt = siteTotal('RMT');

const arrow = (curr, prev) => {
  if (prev === 0 && curr === 0) return '';
  if (prev === 0) return ' :arrow_up:';
  const pct = ((curr - prev) / prev * 100).toFixed(0);
  if (curr > prev) return ' :chart_with_upwards_trend: +' + pct + '%';
  if (curr < prev) return ' :chart_with_downwards_trend: ' + pct + '%';
  return ' :arrow_right: 0%';
};

const atxTotalS = atx.sales + bonus.ATX.s;
const atxTotalP = atx.premium + bonus.ATX.p;
const cltTotalS = clt.sales + bonus.CLT.s;
const cltTotalP = clt.premium + bonus.CLT.p;
const rmtTotalS = rmt.sales + bonus.RMT.s;
const rmtTotalP = rmt.premium + bonus.RMT.p;

const now = new Date();
const h = now.getUTCHours() - 6;
const ampm = h >= 12 ? 'PM' : 'AM';
const h12 = h > 12 ? h-12 : (h===0 ? 12 : h);
const mm = String(now.getUTCMinutes()).padStart(2,'0');
const time = h12+':'+mm+' '+ampm;

const cr = (site, tier) => { const l = leads[site][tier]; return l > 0 ? ((data[site][tier].s/l)*100).toFixed(1)+'%' : '--'; };
const ibCR = (site) => ib[site].leads > 0 ? ((ib[site].sales/ib[site].leads)*100).toFixed(1)+'%' : '--';
const obCR = (site) => ob[site].leads > 0 ? ((ob[site].sales/ob[site].leads)*100).toFixed(1)+'%' : '--';
const tierLine = (site, tier) => { const t = data[site][tier]; return t.n > 0 ? tier+': '+t.s+' sales / '+fmt(t.p)+' / '+cr(site,tier)+' CR' : tier+': --'; };

const totalS = atxTotalS + cltTotalS + rmtTotalS;
const totalP = atxTotalP + cltTotalP + rmtTotalP;
const totalIBLeads = ib.ATX.leads+ib.CLT.leads+ib.RMT.leads;
const totalOBLeads = ob.ATX.leads+ob.CLT.leads+ob.RMT.leads;
const totalIBSales = ib.ATX.sales+ib.CLT.sales+ib.RMT.sales;
const totalOBSales = ob.ATX.sales+ob.CLT.sales+ob.RMT.sales;
const totalIBCR = totalIBLeads > 0 ? ((totalIBSales/totalIBLeads)*100).toFixed(1)+'%' : '--';
const totalOBCR = totalOBLeads > 0 ? ((totalOBSales/totalOBLeads)*100).toFixed(1)+'%' : '--';

const yTotalS = ySites.ATX.s + ySites.CLT.s + ySites.RMT.s;
const yTotalP = ySites.ATX.p + ySites.CLT.p + ySites.RMT.p;
const hasYesterday = yData.length > 0;

const vsYesterday = hasYesterday ? '\n_vs yesterday:_ Sales'+arrow(totalS,yTotalS)+'  |  Premium'+arrow(totalP,yTotalP) : '';

const message = {
  text: 'DSB Production Update - ' + scrapeDate,
  blocks: [
    { type: 'header', text: { type: 'plain_text', text: 'DSB Production Update \u2014 ' + scrapeDate, emoji: true } },
    { type: 'section', text: { type: 'mrkdwn', text: '*'+agents.length+' agents* reported at *'+time+' CST*' } },
    { type: 'divider' },
    { type: 'section', fields: [
      { type: 'mrkdwn', text: '*RMT (Remote)  \u2014  '+rmtTotalS+' sales  |  '+fmt(rmtTotalP)+'*'+(hasYesterday ? arrow(rmtTotalS, ySites.RMT.s)+' vs prior' : '')+'\nIB CR: *'+ibCR('RMT')+'*  |  OB CR: *'+obCR('RMT')+'*\n'+rmt.agents+' agents'+(bonus.RMT.s>0 ? '\n:star: Bonus: '+bonus.RMT.s+' sales / '+fmt(bonus.RMT.p) : '') },
      { type: 'mrkdwn', text: '*CLT (Charlotte)  \u2014  '+cltTotalS+' sales  |  '+fmt(cltTotalP)+'*'+(hasYesterday ? arrow(cltTotalS, ySites.CLT.s)+' vs prior' : '')+'\nIB CR: *'+ibCR('CLT')+'*  |  OB CR: *'+obCR('CLT')+'*\n'+clt.agents+' agents'+(bonus.CLT.s>0 ? '\n:star: Bonus: '+bonus.CLT.s+' sales / '+fmt(bonus.CLT.p) : '') }
    ]},
    { type: 'divider' },
    { type: 'section', text: { type: 'mrkdwn', text: '*Combined:*  *'+totalS+'* sales  |  *'+fmt(totalP)+'* premium\nIB CR: *'+totalIBCR+'*  |  OB CR: *'+totalOBCR+'*'+((bonus.ATX.s+bonus.CLT.s+bonus.RMT.s)>0 ? '\n:star: *Bonus/Custom:*  '+(bonus.ATX.s+bonus.CLT.s+bonus.RMT.s)+' sales  |  '+fmt(bonus.ATX.p+bonus.CLT.p+bonus.RMT.p)+' premium' : '')+vsYesterday } },
    { type: 'context', elements: [{ type: 'mrkdwn', text: 'Report date: '+scrapeDate+'  |  Next update in ~2 hours' }] }
  ]
};

return [{ json: message }];

const payload = $node['Fetch Dataset & Build Payload'].json;
const poolAgents = payload.pool_agents || [];
const poolInventory = payload.pool_inventory || [];

if (poolAgents.length === 0 && poolInventory.length === 0) {
  return [{ json: { skip: true, message: 'No pool data to ingest' } }];
}

return [{
  json: {
    scrape_date: payload.scrape_date,
    agents: poolAgents,
    inventory: poolInventory
  }
}];
